public Object answer(InvocationOnMock invocation) throws Throwable {
    // Check if the method is part of an interface
    if (invocation.getMethod().getDeclaringClass().isInterface()) {
        return getDefaultReturnValue(invocation);
    }

    // Check if the method is abstract
    if (java.lang.reflect.Modifier.isAbstract(invocation.getMethod().getModifiers())) {
        return getDefaultReturnValue(invocation);
    }

    // Call the real method for concrete methods
    return invocation.callRealMethod();
}

private Object getDefaultReturnValue(InvocationOnMock invocation) {
    Class<?> returnType = invocation.getMethod().getReturnType();
    if (returnType.isPrimitive()) {
        if (returnType == boolean.class) return false;
        if (returnType == int.class) return 0;
        if (returnType == long.class) return 0L;
        if (returnType == double.class) return 0.0;
        if (returnType == float.class) return 0.0f;
        if (returnType == char.class) return '\u0000';
        if (returnType == byte.class) return (byte) 0;
        if (returnType == short.class) return (short) 0;
    }
    return null; // For non-primitive types, return null
}
